const event = $input.first().json;
const message = event.message || {};
const from = message.from || {};
const text = String(message.text || '').trim();
const fullName = [from.first_name, from.last_name].filter(Boolean).join(' ').trim();
return [{
  json: {
    spreadsheet_id: 'YOUR_HELPDESKBOT_DB_SPREADSHEET_ID',
    telegram_user: String(from.id || ''),
    chat_id: String((message.chat && message.chat.id) || from.id || ''),
    username: from.username || '',
    first_name: from.first_name || '',
    last_name: from.last_name || '',
    full_name: fullName || from.username || 'Usuario',
    text,
    message_id: String(message.message_id || ''),
    input_timestamp: new Date().toISOString()
  }
}];

const base = $('Normalize Input').all()[0].json;
const rows = $input.all().map(i => i.json).filter(r => r && Object.keys(r).length);
const row = rows.find(r => String(r.telegram_user || '') === String(base.telegram_user)) || null;
const activoRaw = row ? row.activo : null;
const activo = activoRaw === true || ['true','1','si','sí','yes','activo'].includes(String(activoRaw || '').toLowerCase());
const rol = String((row && row.rol) || 'user').toLowerCase();
const nombre = (row && row.nombre) || base.full_name || base.username || 'Usuario';
const allowed = !!row && activo;
const state = allowed ? { screen: 'main_menu' } : { screen: 'blocked', reason: row ? 'inactive' : 'not_found' };
return [{
  json: {
    ...base,
    nombre,
    rol,
    user_allowed: allowed,
    response_text: allowed ? '' : 'Lo siento, tu usuario no está activo en HelpDeskBot. Por favor contacta al administrador para habilitar tu acceso.',
    log_timestamp: new Date().toISOString(),
    log_pantalla: allowed ? 'pre_auth_ok' : 'acceso_denegado',
    log_opcion: base.text,
    log_resultado: JSON.stringify(state)
  }
}];

const ctx = $('Normalize User').all()[0].json;

const rows = $input.all()
  .map(i => i.json)
  .filter(r => r && r.timestamp);

// Asegura que la memoria se lea por timestamp, no por el orden accidental del nodo.
rows.sort((a, b) => String(a.timestamp || '').localeCompare(String(b.timestamp || '')));

let session = { screen: 'main_menu' };
if (rows.length) {
  const latest = rows[rows.length - 1];
  if (latest.resultado) {
    try {
      const parsed = JSON.parse(latest.resultado);
      if (parsed && typeof parsed === 'object') {
        session = parsed;
      }
    } catch (e) {
      session = { screen: 'main_menu' };
    }
  }
}

const textRaw = String(ctx.text || '').trim();

const validOptionsByScreen = {
  main_menu: [
    '0 Ayuda',
    '1 Crear solicitud',
    '2 Consultar estado de solicitud',
    '3 Mis solicitudes',
    '4 Reportes',
    '5 Configuración'
  ],
  awaiting_create_type: [
    '1 Soporte técnico',
    '2 Solicitud administrativa',
    '3 Consulta general',
    '9 Cancelar'
  ],
  awaiting_create_priority: [
    '1 Alta',
    '2 Media',
    '3 Baja',
    '9 Cancelar'
  ],
  awaiting_create_description: [
    'Texto libre con descripción del problema',
    '9 Cancelar'
  ],
  awaiting_create_confirm: [
    '1 Confirmar',
    '9 Cancelar',
    'También puede pedir cambiar tipo, prioridad o descripción'
  ],
  awaiting_query_ticket_id: [
    'ID de ticket, por ejemplo HD-20260425-123456',
    '9 Cancelar'
  ],
  awaiting_report_option: [
    '1 Resumen general',
    '2 Cambiar estado de ticket',
    '9 Cancelar'
  ],
  awaiting_admin_status_ticket: [
    'ID de ticket',
    '9 Cancelar'
  ],
  awaiting_admin_status_value: [
    '1 Abierto',
    '2 En proceso',
    '3 Cerrado',
    '9 Cancelar'
  ]
};

const currentScreen = session.screen || 'main_menu';
const currentOptions = validOptionsByScreen[currentScreen] || validOptionsByScreen.main_menu;

const systemText = [
  'Eres el interpretador de intención de HelpDeskBot.',
  'NO ejecutes acciones. Solo devuelve JSON válido.',
  'Tu tarea es traducir el texto libre del usuario a una intención segura para un flujo n8n.',
  'Respeta el estado actual de la conversación.',
  'Si el usuario saluda o pregunta algo mientras está dentro de un paso del formulario, no rompas el flujo: devuelve smalltalk y una respuesta breve que lo guíe.',
  'Si el usuario confirma con palabras como "sí", "confirmo", "dale", "ok", "crear", devuelve intent confirm.',
  'Si el usuario quiere cancelar, salir, reiniciar o volver al menú, devuelve cancel o menu según corresponda.',
  'Si el usuario quiere modificar un borrador, usa change_field e indica field_to_change.',
  'Valores permitidos para tipo: "Soporte técnico", "Solicitud administrativa", "Consulta general".',
  'Valores permitidos para prioridad: "Alta", "Media", "Baja".',
  'Devuelve únicamente JSON, sin markdown.'
].join('\n');

const userPrompt = {
  contexto: {
    pantalla_actual: currentScreen,
    opciones_validas: currentOptions,
    borrador_actual: {
      tipo: session.tipo || null,
      prioridad: session.prioridad || null,
      descripcion: session.descripcion || null,
      ticket_id: session.ticket_id || null
    },
    rol_usuario: ctx.rol || 'user'
  },
  mensaje_usuario: textRaw,
  salida_esperada: {
    intent: 'menu | help | cancel | confirm | create_ticket | query_ticket | my_tickets | reports | config | change_field | smalltalk | unknown',
    tipo: 'Soporte técnico | Solicitud administrativa | Consulta general | null',
    prioridad: 'Alta | Media | Baja | null',
    descripcion: 'string | null',
    ticket_id: 'string | null',
    field_to_change: 'tipo | prioridad | descripcion | estado | null',
    reply: 'respuesta breve en español si intent es smalltalk/unknown o si hace falta guiar al usuario',
    confidence: 'número entre 0 y 1'
  },
  ejemplos: [
    {
      entrada: 'sí, confirmar',
      salida: { intent: 'confirm', confidence: 0.95 }
    },
    {
      entrada: 'quiero cambiar la prioridad a alta',
      salida: { intent: 'change_field', field_to_change: 'prioridad', prioridad: 'Alta', confidence: 0.95 }
    },
    {
      entrada: 'hola',
      salida: { intent: 'smalltalk', reply: '¡Hola! Sigo aquí. Estábamos en el paso actual; dime una opción válida o qué quieres cambiar.', confidence: 0.9 }
    },
    {
      entrada: 'quiero crear un ticket urgente porque mi pc no prende',
      salida: { intent: 'create_ticket', tipo: 'Soporte técnico', prioridad: 'Alta', descripcion: 'Mi PC no prende', confidence: 0.95 }
    }
  ]
};

return [{
  json: {
    ...ctx,
    session,
    session_screen: currentScreen,
    valid_options: currentOptions,
    gemini_request_body: {
      systemInstruction: {
        parts: [
          {
            text: systemText
          }
        ]
      },
      contents: [
        {
          role: 'user',
          parts: [
            {
              text: JSON.stringify(userPrompt, null, 2)
            }
          ]
        }
      ],
      generationConfig: {
        temperature: 0.2,
        maxOutputTokens: 700,
        responseMimeType: 'application/json'
      }
    }
  }
}];

const ctx = $('Build Gemini Context').all()[0].json;
const response = $input.first().json || {};

function stripAccents(value) {
  return String(value || '').normalize('NFD').replace(/[\u0300-\u036f]/g, '');
}

function fallbackIntent(textRaw) {
  const raw = String(textRaw || '').trim();
  const text = stripAccents(raw.toLowerCase());

  if (!raw) {
    return { intent: 'unknown', confidence: 0.2, reply: 'No recibí texto. Por favor escribe una opción o dime qué necesitas.' };
  }

  if (['/start', 'start', 'menu', 'menú', '0', 'ayuda', 'help'].includes(raw.toLowerCase())) {
    return { intent: raw === '0' || text.includes('ayuda') || text === 'help' ? 'help' : 'menu', confidence: 0.9 };
  }

  if (raw === '9' || /\b(cancelar|cancela|salir|volver|reiniciar|menu principal|menú principal)\b/.test(text)) {
    return { intent: text.includes('menu') ? 'menu' : 'cancel', confidence: 0.9 };
  }

  if (/^(1|si|sí|s|ok|okay|dale|listo|confirmo|confirmar|crear|enviar|correcto)$/.test(raw.toLowerCase())) {
    return { intent: 'confirm', confidence: 0.75 };
  }

  const ticketMatch = raw.match(/HD-\d{8}-\d{3,}/i);
  if (ticketMatch || /\b(estado|consultar|consulta|ticket|solicitud)\b/.test(text) && /\bhd[-\s]?\d+/i.test(raw)) {
    return { intent: 'query_ticket', ticket_id: ticketMatch ? ticketMatch[0].toUpperCase() : raw, confidence: 0.75 };
  }

  if (/\b(mis solicitudes|mis tickets|ver solicitudes|ver tickets)\b/.test(text)) {
    return { intent: 'my_tickets', confidence: 0.85 };
  }

  if (/\b(reporte|reportes|resumen|estadisticas|estadísticas)\b/.test(text)) {
    return { intent: 'reports', confidence: 0.85 };
  }

  if (/\b(configuracion|configuración|ajustes)\b/.test(text)) {
    return { intent: 'config', confidence: 0.85 };
  }

  if (/\b(cambiar|modificar|editar|corrige|corregir)\b/.test(text)) {
    let field = null;
    if (/\b(tipo|categoria|categoría)\b/.test(text)) field = 'tipo';
    if (/\b(prioridad|urgencia)\b/.test(text)) field = 'prioridad';
    if (/\b(descripcion|descripción|detalle|problema)\b/.test(text)) field = 'descripcion';
    return { intent: 'change_field', field_to_change: field, confidence: 0.65 };
  }

  if (/\b(hola|buenas|buenos dias|buenos días|buenas tardes|buenas noches|hey|gracias)\b/.test(text)) {
    return { intent: 'smalltalk', confidence: 0.85, reply: '¡Hola! Sigo aquí para ayudarte. Podemos continuar con el paso actual o volver al menú.' };
  }

  if (/\b(crear|abrir|registrar|nuevo|ticket|solicitud|problema|falla|error|soporte|urgente|no funciona|dañado|danado)\b/.test(text)) {
    return { intent: 'create_ticket', descripcion: raw, confidence: 0.65 };
  }

  return { intent: 'unknown', confidence: 0.35, reply: 'No entendí completamente. Puedes escribir una opción del menú o decirme qué necesitas en una frase.' };
}

function extractGeminiText(payload) {
  const parts = payload?.candidates?.[0]?.content?.parts || [];
  const textPart = parts.find(p => typeof p.text === 'string');
  return textPart ? textPart.text : '';
}

let raw = extractGeminiText(response);
let parsed = null;

try {
  parsed = JSON.parse(raw);
} catch (e) {
  const match = String(raw || '').match(/\{[\s\S]*\}/);
  if (match) {
    try {
      parsed = JSON.parse(match[0]);
    } catch (e2) {
      parsed = null;
    }
  }
}

const fallback = fallbackIntent(ctx.text);
let ai = parsed && typeof parsed === 'object' ? parsed : fallback;

const allowedIntents = [
  'menu',
  'help',
  'cancel',
  'confirm',
  'create_ticket',
  'query_ticket',
  'my_tickets',
  'reports',
  'config',
  'change_field',
  'smalltalk',
  'unknown'
];

if (!allowedIntents.includes(String(ai.intent || ''))) {
  ai.intent = fallback.intent;
}

ai.intent = String(ai.intent || fallback.intent || 'unknown');
ai.tipo = ai.tipo || null;
ai.prioridad = ai.prioridad || null;
ai.descripcion = ai.descripcion || null;
ai.ticket_id = ai.ticket_id || null;
ai.field_to_change = ai.field_to_change || null;
ai.reply = ai.reply || fallback.reply || null;
ai.confidence = Number(ai.confidence || fallback.confidence || 0.3);

return [{
  json: {
    ...ctx,
    ai_intent: ai,
    ai_raw_response: String(raw || '').slice(0, 2000),
    ai_provider_error: response.error ? JSON.stringify(response.error).slice(0, 1000) : null
  }
}];

const ctx = $input.first().json;
const session = ctx.session && typeof ctx.session === 'object' ? ctx.session : { screen: 'main_menu' };
const ai = ctx.ai_intent && typeof ctx.ai_intent === 'object' ? ctx.ai_intent : {};

const textRaw = String(ctx.text || '').trim();
const textLower = textRaw.toLowerCase();
const now = new Date().toISOString();

function stripAccents(value) {
  return String(value || '').normalize('NFD').replace(/[\u0300-\u036f]/g, '');
}

const text = stripAccents(textLower);
const isAdmin = ['admin', 'agent', 'soporte', 'support'].includes(String(ctx.rol || '').toLowerCase());

const mainMenu = 'Hola, soy HelpDeskBot 👋\n\nEstoy aquí para ayudarte con solicitudes de soporte\nde forma rápida y ordenada.\n\nPuedes escribir el número de la opción o decirme con tus palabras lo que necesitas.\n\nMenú principal:\n0. Ayuda\n1. Crear solicitud\n2. Consultar estado de solicitud\n3. Mis solicitudes\n4. Reportes\n5. Configuración';

const createMenu = 'Vamos a crear una solicitud.\n\nPuedes responder con el número o escribirlo con tus palabras.\n\nSelecciona el tipo:\n1. Soporte técnico\n2. Solicitud administrativa\n3. Consulta general\n9. Cancelar';

const priorityMenu = 'Selecciona la prioridad:\n1. Alta\n2. Media\n3. Baja\n9. Cancelar';

const helpText = mainMenu + '\n\nEjemplos:\n- "Crear ticket urgente porque mi PC no prende"\n- "Consultar HD-20260425-123456"\n- "Mis solicitudes"\n\nTip: puedes escribir 9 o "cancelar" para salir de cualquier proceso.';

const cancelText = 'Operación cancelada.\n\n' + mainMenu;

const configText = 'Configuración\n\nPor ahora no hay opciones editables desde Telegram.\n\n' + mainMenu;

const reportMenu = 'Reportes\n\n1. Resumen general\n2. Cambiar estado de ticket\n9. Cancelar';

function simple(response, nextState) {
  const state = nextState && typeof nextState === 'object' ? nextState : { screen: 'main_menu' };
  return [{
    json: {
      ...ctx,
      route_index: 0,
      response_text: response,
      log_timestamp: now,
      log_pantalla: state.screen || 'main_menu',
      log_opcion: textRaw,
      log_resultado: JSON.stringify(state)
    }
  }];
}

function route(index, extra = {}) {
  return [{
    json: {
      ...ctx,
      ...extra,
      route_index: index
    }
  }];
}

function firstFilled(...values) {
  for (const value of values) {
    if (value !== undefined && value !== null && String(value).trim() !== '') {
      return value;
    }
  }
  return null;
}

function cleanDescription(value) {
  const v = String(value || '').trim();
  if (!v) return null;
  if (['1', '2', '3', '4', '5', '9', '0'].includes(v)) return null;
  if (/^(si|sí|s|ok|okay|confirmo|confirmar|dale|listo|cancelar|menu|menú)$/i.test(v)) return null;
  return v;
}

function normalizeTipo(value) {
  const v = stripAccents(String(value || '').toLowerCase()).trim();
  if (!v) return null;

  if (
    v === '1' ||
    v.includes('soporte tecnico') ||
    v.includes('tecnico') ||
    v.includes('soporte') ||
    v.includes('pc') ||
    v.includes('computador') ||
    v.includes('computadora') ||
    v.includes('laptop') ||
    v.includes('internet') ||
    v.includes('wifi') ||
    v.includes('correo') ||
    v.includes('impresora') ||
    v.includes('sistema') ||
    v.includes('chatbot') ||
    v.includes('bot')
  ) {
    return 'Soporte técnico';
  }

  if (
    v === '2' ||
    v.includes('solicitud administrativa') ||
    v.includes('administrativa') ||
    v.includes('administrativo') ||
    v.includes('documento') ||
    v.includes('certificado') ||
    v.includes('permiso')
  ) {
    return 'Solicitud administrativa';
  }

  if (
    v === '3' ||
    v.includes('consulta general') ||
    v === 'consulta' ||
    v.includes('pregunta') ||
    v.includes('informacion') ||
    v.includes('información') ||
    v.includes('general')
  ) {
    return 'Consulta general';
  }

  return null;
}

function normalizePriority(value) {
  const v = stripAccents(String(value || '').toLowerCase()).trim();
  if (!v) return null;

  if (
    v === '1' ||
    v.includes('alta') ||
    v.includes('urgente') ||
    v.includes('critica') ||
    v.includes('crítica') ||
    v.includes('grave') ||
    v.includes('bloqueado') ||
    v.includes('no puedo trabajar')
  ) {
    return 'Alta';
  }

  if (
    v === '2' ||
    v.includes('media') ||
    v.includes('normal') ||
    v.includes('moderada')
  ) {
    return 'Media';
  }

  if (
    v === '3' ||
    v.includes('baja') ||
    v.includes('no urgente') ||
    v.includes('cuando puedan') ||
    v.includes('leve')
  ) {
    return 'Baja';
  }

  return null;
}

function ticketIdFrom(value) {
  const raw = String(value || '').trim();
  const match = raw.match(/HD-\d{8}-\d{3,}/i);
  if (match) return match[0].toUpperCase();
  return raw || null;
}

function confirmationText(draft) {
  return 'Confirma la solicitud:\n\n' +
    'Tipo: ' + draft.tipo + '\n' +
    'Prioridad: ' + draft.prioridad + '\n' +
    'Descripción: ' + draft.descripcion + '\n\n' +
    '1. Confirmar\n' +
    '9. Cancelar\n\n' +
    'También puedes decir "confirmar", "cancelar" o "cambiar prioridad a alta".';
}

function guideCurrentDraft(prefix = '') {
  const draft = {
    tipo: session.tipo,
    prioridad: session.prioridad,
    descripcion: session.descripcion
  };

  const base = draft.tipo && draft.prioridad && draft.descripcion
    ? confirmationText(draft)
    : mainMenu;

  return (prefix ? prefix + '\n\n' : '') + base;
}

function aiReplyOr(defaultText) {
  const reply = String(ai.reply || '').trim();
  if (reply && reply.length <= 1000) return reply;
  return defaultText;
}

function promptNextFromDraft(draft) {
  if (!draft.tipo) {
    return simple(createMenu, {
      screen: 'awaiting_create_type',
      prioridad: draft.prioridad || undefined,
      descripcion: draft.descripcion || undefined
    });
  }

  if (!draft.prioridad) {
    return simple(priorityMenu, {
      screen: 'awaiting_create_priority',
      tipo: draft.tipo,
      descripcion: draft.descripcion || undefined
    });
  }

  if (!draft.descripcion) {
    return simple('Describe el problema o solicitud.\n\n9. Cancelar', {
      screen: 'awaiting_create_description',
      tipo: draft.tipo,
      prioridad: draft.prioridad
    });
  }

  return simple(confirmationText(draft), {
    screen: 'awaiting_create_confirm',
    tipo: draft.tipo,
    prioridad: draft.prioridad,
    descripcion: draft.descripcion
  });
}

function draftFromAI({ allowInferFromText = true, keepSession = true } = {}) {
  const descriptionCandidate = cleanDescription(firstFilled(ai.descripcion, keepSession ? session.descripcion : null));
  const inferenceText = allowInferFromText
    ? firstFilled(ai.tipo, ai.prioridad, descriptionCandidate, textRaw)
    : firstFilled(ai.tipo, ai.prioridad, descriptionCandidate);

  return {
    tipo: normalizeTipo(firstFilled(ai.tipo, keepSession ? session.tipo : null, allowInferFromText ? inferenceText : null)),
    prioridad: normalizePriority(firstFilled(ai.prioridad, keepSession ? session.prioridad : null, allowInferFromText ? inferenceText : null)),
    descripcion: descriptionCandidate
  };
}

function isSmalltalkIntent() {
  return ai.intent === 'smalltalk';
}

function isConfirmIntent() {
  return textRaw === '1' || ai.intent === 'confirm' || /^(si|sí|s|ok|okay|dale|listo|confirmo|confirmar|crear|enviar|correcto)$/i.test(textRaw);
}

function isGlobalMenuIntent() {
  return ['/start', 'start', 'menu', 'menú', '0', 'ayuda', 'help'].includes(textLower) || ai.intent === 'menu' || ai.intent === 'help';
}

function isGlobalCancelIntent() {
  return textRaw === '9' || ai.intent === 'cancel';
}

// Intenciones globales
if (isGlobalMenuIntent()) {
  return simple(helpText, { screen: 'main_menu' });
}

if (isGlobalCancelIntent()) {
  return simple(cancelText, { screen: 'main_menu' });
}

// Paso: seleccionar tipo
if (session.screen === 'awaiting_create_type') {
  const selectedTipo = normalizeTipo(firstFilled(ai.tipo, textRaw));

  if (!selectedTipo) {
    return simple(
      aiReplyOr('No pude identificar el tipo de solicitud. Elige una opción o escribe "soporte técnico", "administrativa" o "consulta general".') +
      '\n\n' + createMenu,
      {
        ...session,
        screen: 'awaiting_create_type'
      }
    );
  }

  const draft = {
    tipo: selectedTipo,
    prioridad: normalizePriority(firstFilled(ai.prioridad, session.prioridad)),
    descripcion: cleanDescription(firstFilled(ai.descripcion, session.descripcion))
  };

  return promptNextFromDraft(draft);
}

// Paso: seleccionar prioridad
if (session.screen === 'awaiting_create_priority') {
  const selectedPriority = normalizePriority(firstFilled(ai.prioridad, textRaw));

  if (!selectedPriority) {
    return simple(
      aiReplyOr('No pude identificar la prioridad. Puedes escribir alta, media o baja.') +
      '\n\n' + priorityMenu,
      {
        ...session,
        screen: 'awaiting_create_priority'
      }
    );
  }

  const draft = {
    tipo: normalizeTipo(session.tipo),
    prioridad: selectedPriority,
    descripcion: cleanDescription(firstFilled(ai.descripcion, session.descripcion))
  };

  return promptNextFromDraft(draft);
}

// Paso: escribir descripción
if (session.screen === 'awaiting_create_description') {
  if (isSmalltalkIntent() && !cleanDescription(ai.descripcion)) {
    return simple(
      aiReplyOr('¡Hola! Para continuar necesito que me describas el problema o solicitud.') +
      '\n\nDescribe el problema o solicitud.\n\n9. Cancelar',
      {
        ...session,
        screen: 'awaiting_create_description'
      }
    );
  }

  const description = cleanDescription(firstFilled(ai.descripcion, textRaw));

  if (!description) {
    return simple(
      'La descripción es obligatoria.\n\nDescribe el problema o solicitud.\n\n9. Cancelar',
      {
        ...session,
        screen: 'awaiting_create_description'
      }
    );
  }

  const draft = {
    tipo: normalizeTipo(session.tipo),
    prioridad: normalizePriority(session.prioridad),
    descripcion: description
  };

  return promptNextFromDraft(draft);
}

// Paso: confirmar solicitud
if (session.screen === 'awaiting_create_confirm') {
  if (isConfirmIntent()) {
    if (!session.tipo || !session.prioridad || !session.descripcion) {
      return promptNextFromDraft({
        tipo: normalizeTipo(session.tipo),
        prioridad: normalizePriority(session.prioridad),
        descripcion: cleanDescription(session.descripcion)
      });
    }

    return route(1, {
      ticket_tipo: session.tipo,
      ticket_prioridad: session.prioridad,
      ticket_descripcion: session.descripcion
    });
  }

  if (ai.intent === 'change_field' || ai.intent === 'create_ticket') {
    const wantsType = ai.field_to_change === 'tipo';
    const wantsPriority = ai.field_to_change === 'prioridad';
    const wantsDescription = ai.field_to_change === 'descripcion';

    const updatedDraft = {
      tipo: normalizeTipo(firstFilled(ai.tipo, session.tipo)),
      prioridad: normalizePriority(firstFilled(ai.prioridad, session.prioridad)),
      descripcion: cleanDescription(firstFilled(ai.descripcion, session.descripcion))
    };

    if (wantsType && !ai.tipo) {
      return simple(createMenu, {
        screen: 'awaiting_create_type',
        prioridad: updatedDraft.prioridad,
        descripcion: updatedDraft.descripcion
      });
    }

    if (wantsPriority && !ai.prioridad) {
      return simple(priorityMenu, {
        screen: 'awaiting_create_priority',
        tipo: updatedDraft.tipo,
        descripcion: updatedDraft.descripcion
      });
    }

    if (wantsDescription && !ai.descripcion) {
      return simple('Escribe la nueva descripción de la solicitud.\n\n9. Cancelar', {
        screen: 'awaiting_create_description',
        tipo: updatedDraft.tipo,
        prioridad: updatedDraft.prioridad
      });
    }

    return promptNextFromDraft(updatedDraft);
  }

  return simple(
    aiReplyOr('Estamos en la confirmación de la solicitud. Puedes confirmar, cancelar o pedirme cambiar algún dato.') +
    '\n\n' +
    confirmationText({
      tipo: session.tipo,
      prioridad: session.prioridad,
      descripcion: session.descripcion
    }),
    session
  );
}

// Paso: consultar ticket
if (session.screen === 'awaiting_query_ticket_id') {
  if (isSmalltalkIntent()) {
    return simple(
      aiReplyOr('Sigo aquí. Para consultar el estado necesito el ID del ticket, por ejemplo HD-20260425-123456.') +
      '\n\n9. Cancelar',
      { screen: 'awaiting_query_ticket_id' }
    );
  }

  const lookup = ticketIdFrom(firstFilled(ai.ticket_id, textRaw));

  if (!lookup) {
    return simple(
      'Debes escribir un ID de ticket.\n\nEjemplo: HD-20260425-123456\n\n9. Cancelar',
      { screen: 'awaiting_query_ticket_id' }
    );
  }

  return route(2, { lookup_ticket_id: lookup });
}

// Paso: reportes
if (session.screen === 'awaiting_report_option') {
  if (!isAdmin) {
    return simple('No tienes permisos para acceder a reportes.\n\n' + mainMenu, { screen: 'main_menu' });
  }

  if (textRaw === '1' || ai.intent === 'reports') {
    return route(4);
  }

  if (textRaw === '2' || ai.intent === 'change_field') {
    return simple('Escribe el ID del ticket al que deseas cambiar el estado.\n\n9. Cancelar', {
      screen: 'awaiting_admin_status_ticket'
    });
  }

  return simple(
    aiReplyOr('No pude identificar la opción de reportes. Elige 1 para resumen o 2 para cambiar estado.') +
    '\n\n' + reportMenu,
    { screen: 'awaiting_report_option' }
  );
}

// Paso admin: pedir ticket
if (session.screen === 'awaiting_admin_status_ticket') {
  const lookup = ticketIdFrom(firstFilled(ai.ticket_id, textRaw));

  if (!lookup || isSmalltalkIntent()) {
    return simple('Escribe el ID del ticket al que deseas cambiar el estado.\n\n9. Cancelar', {
      screen: 'awaiting_admin_status_ticket'
    });
  }

  return route(5, { lookup_ticket_id: lookup });
}

// Paso admin: seleccionar estado
if (session.screen === 'awaiting_admin_status_value') {
  const statusMap = {
    '1': 'Abierto',
    '2': 'En proceso',
    '3': 'Cerrado'
  };

  let nuevoEstado = statusMap[textRaw];

  const aiStatus = stripAccents(String(firstFilled(ai.nuevo_estado, ai.estado, ai.descripcion, textRaw) || '').toLowerCase());
  if (!nuevoEstado) {
    if (aiStatus.includes('abierto')) nuevoEstado = 'Abierto';
    if (aiStatus.includes('proceso')) nuevoEstado = 'En proceso';
    if (aiStatus.includes('cerrado') || aiStatus.includes('cerrar')) nuevoEstado = 'Cerrado';
  }

  if (!nuevoEstado) {
    return simple(
      'Estado inválido.\n\nSelecciona el nuevo estado:\n1. Abierto\n2. En proceso\n3. Cerrado\n9. Cancelar',
      session
    );
  }

  return route(6, {
    lookup_ticket_id: session.ticket_id,
    nuevo_estado: nuevoEstado
  });
}

// Menú principal rígido + natural
if (textRaw === '1') {
  return simple(createMenu, { screen: 'awaiting_create_type' });
